    */
  return (
    <div className="bg-branco w-3/4 h-28 rounded-full inline-flex">
      <div className="bg-vermelho w-28 h-28 rounded-full inline-flex">
        {/*<h1 className="text-white text-7xl self-center mx-auto">1°</h1> */}
      </div>

      <div className="self-center ml-6">
        <h1 className="text-2xl font-bold text-verde">Nome: {aluno.nome}</h1>
        <h2 className="text-xl font-bold text-verde">Turma: {aluno.turma}</h2>
      </div>

      <div>
        <h1 className="text-verde text-7xl self-center">{aluno.pontuacao}</h1>
        <h2 c>Pontos</h2>
      </div>
    </div>
  );
}
